import React, { useState, useEffect, useRef } from 'react';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';
import '../styles/profile.css';

const Profile = () => {
  const { user, updateUser } = useAuth();
  const fileRef = useRef();

  const [form, setForm] = useState({
    name: '',
    phone: '',
    bio: '',
    skills: '',
    education: '',
    experience: '',
  });
  const [loading, setLoading] = useState(false);
  const [toast, setToast] = useState(null);
  const [uploading, setUploading] = useState(false);
  const [previewUrl, setPreviewUrl] = useState(null);

  useEffect(() => {
    if (user) {
      setForm({
        name: user.name || '',
        phone: user.phone || '',
        bio: user.bio || '',
        skills: (user.skills || []).join(', '),
        education: user.education || '',
        experience: user.experience || '',
      });
      if (user.profilePicture) {
        setPreviewUrl(`http://localhost:5000/${user.profilePicture}`);
      }
    }
  }, [user]);

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const payload = {
        ...form,
        skills: form.skills.split(',').map(s => s.trim()).filter(Boolean),
      };
      const res = await axios.put('/api/auth/profile', payload);
      updateUser(res.data);
      showToast('✅ Profile updated successfully!', 'success');
    } catch (err) {
      showToast(err.response?.data?.message || 'Update failed.', 'error');
    } finally {
      setLoading(false);
    }
  };

  const handlePictureChange = async (e) => {
    const file = e.target.files[0];
    if (!file) return;
    if (!file.type.startsWith('image/')) {
      showToast('Only image files are allowed.', 'error');
      return;
    }
    if (file.size > 2 * 1024 * 1024) {
      showToast('Image must be under 2MB.', 'error');
      return;
    }

    // Preview
    const reader = new FileReader();
    reader.onload = (ev) => setPreviewUrl(ev.target.result);
    reader.readAsDataURL(file);

    setUploading(true);
    try {
      const fd = new FormData();
      fd.append('profilePicture', file);
      const res = await axios.put('/api/auth/profile', fd, {
        headers: { 'Content-Type': 'multipart/form-data' },
      });
      updateUser(res.data);
      showToast('🖼️ Profile picture updated!', 'success');
    } catch (err) {
      showToast('Photo upload failed.', 'error');
      setPreviewUrl(user?.profilePicture ? `http://localhost:5000/${user.profilePicture}` : null);
    } finally {
      setUploading(false);
    }
  };

  const showToast = (message, type) => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 3500);
  };

  const initials = user?.name?.split(' ').map(n => n[0]).join('').slice(0, 2).toUpperCase() || 'U';

  return (
    <div className="profile-page page-content">
      {toast && <div className={`toast toast-${toast.type}`}>{toast.message}</div>}

      <div className="container profile-container">
        {/* Page Header */}
        <div className="profile-page-header">
          <h1>My Profile</h1>
          <p>Manage your personal information and career details</p>
        </div>

        <div className="profile-layout">
          {/* Left: Avatar Card */}
          <div className="profile-sidebar">
            <div className="profile-avatar-card">
              <div className="profile-avatar-wrap">
                <div className="profile-avatar">
                  {previewUrl
                    ? <img src={previewUrl} alt="Profile" />
                    : initials}
                </div>
                {uploading && <div className="avatar-uploading-overlay"><span className="spinner-dark" /></div>}
              </div>
              <button
                className="btn-change-photo"
                onClick={() => fileRef.current.click()}
                disabled={uploading}
              >
                {uploading ? 'Uploading...' : '📷 Change Photo'}
              </button>
              <input
                ref={fileRef}
                type="file"
                accept="image/*"
                style={{ display: 'none' }}
                onChange={handlePictureChange}
              />
              <p className="photo-hint">JPG, PNG up to 2 MB</p>
            </div>

            {/* Info Summary */}
            <div className="profile-info-card">
              <div className="profile-info-item">
                <span className="profile-info-icon">✉️</span>
                <div>
                  <div className="profile-info-label">Email</div>
                  <div className="profile-info-value">{user?.email}</div>
                </div>
              </div>
              {form.phone && (
                <div className="profile-info-item">
                  <span className="profile-info-icon">📞</span>
                  <div>
                    <div className="profile-info-label">Phone</div>
                    <div className="profile-info-value">{form.phone}</div>
                  </div>
                </div>
              )}
              <div className="profile-info-item">
                <span className="profile-info-icon">🛡️</span>
                <div>
                  <div className="profile-info-label">Account Type</div>
                  <div className="profile-info-value" style={{ textTransform: 'capitalize' }}>
                    {user?.role || 'user'}
                  </div>
                </div>
              </div>
            </div>
          </div>

          {/* Right: Edit Form */}
          <div className="profile-main">
            <form onSubmit={handleSubmit} className="profile-form">

              {/* Personal */}
              <div className="profile-section">
                <h2 className="profile-section-title">Personal Information</h2>
                <div className="profile-form-grid">
                  <div className="profile-form-group">
                    <label>Full Name *</label>
                    <input
                      name="name"
                      value={form.name}
                      onChange={handleChange}
                      placeholder="John Doe"
                      required
                    />
                  </div>
                  <div className="profile-form-group">
                    <label>Phone Number</label>
                    <input
                      name="phone"
                      value={form.phone}
                      onChange={handleChange}
                      placeholder="+91 9876543210"
                    />
                  </div>
                  <div className="profile-form-group full">
                    <label>Bio / Summary</label>
                    <textarea
                      name="bio"
                      value={form.bio}
                      onChange={handleChange}
                      placeholder="Write a short summary about yourself, your goals, and what you bring to the table..."
                      rows="4"
                    />
                  </div>
                </div>
              </div>

              {/* Skills */}
              <div className="profile-section">
                <h2 className="profile-section-title">Skills</h2>
                <div className="profile-form-group">
                  <label>Skills (comma separated)</label>
                  <input
                    name="skills"
                    value={form.skills}
                    onChange={handleChange}
                    placeholder="React, Node.js, Python, SQL, Figma..."
                  />
                </div>
                {form.skills && (
                  <div className="skills-preview">
                    {form.skills.split(',').map(s => s.trim()).filter(Boolean).map(s => (
                      <span key={s} className="skill-pill">{s}</span>
                    ))}
                  </div>
                )}
              </div>

              {/* Career Details */}
              <div className="profile-section">
                <h2 className="profile-section-title">Career Details</h2>
                <div className="profile-form-grid">
                  <div className="profile-form-group full">
                    <label>Education</label>
                    <textarea
                      name="education"
                      value={form.education}
                      onChange={handleChange}
                      placeholder="B.Tech Computer Science — XYZ University (2020–2024)"
                      rows="3"
                    />
                  </div>
                  <div className="profile-form-group full">
                    <label>Work Experience</label>
                    <textarea
                      name="experience"
                      value={form.experience}
                      onChange={handleChange}
                      placeholder="Frontend Intern at ABC Corp (June–Aug 2023) — Built React components, improved UI performance..."
                      rows="3"
                    />
                  </div>
                </div>
              </div>

              {/* Save */}
              <div className="profile-form-footer">
                <button type="submit" className="btn-primary" disabled={loading}>
                  {loading ? <><span className="spinner" /> Saving...</> : '💾 Save Changes'}
                </button>
              </div>

            </form>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Profile;
